module RefModule (
  input clk,
  input reset,
  input in,
  output reg pulse);reg in_delayed;
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
	if (reset) begin
		in_delayed <= 0;
		pulse <= 0;
	end else begin
		pulse <= in & ~in_delayed;
		in_delayed <= in;
	end
end
endmodule
